export const getRIBALabelFull = (stageLink: string) => {
  if (!stageLink) return 'Universal';
  
  // Mapping for full labels (handles both codes and descriptive IDs)
  const mapping: Record<string, string> = {
    // S-Codes
    'S0': 'Strategic Definition',
    'S1': 'Preparation & Briefing',
    'S2': 'Concept Design',
    'S3': 'Spatial Coordination',
    'S4': 'Technical Design',
    'S5': 'Construction',
    'S6': 'Handover',
    'S7': 'Use',
    // Descriptive IDs from STAGES
    'strategic': 'Stage 0-1: Strategic Definition',
    'pre-construction': 'Stage 2-4: Design & Planning',
    'procurement': 'Stage 3-4: Procurement',
    'mobilisation': 'Stage 5: Mobilisation',
    'construction': 'Stage 5-6: Construction',
    'handover': 'Stage 6-7: Handover & Closeout',
    'all': 'All Stages'
  };

  if (stageLink.includes('-')) {
    const parts = stageLink.split('-');
    const labels = parts.map(p => {
      // Handle shorthands like "S0-7" or "0-7"
      const key = p.startsWith('S') ? p : `S${p}`;
      return mapping[key] || mapping[p] || p;
    });
    // If it's something like "0-1", keep it clean
    if (parts.every(p => !isNaN(Number(p)))) return stageLink;
    return `${stageLink}: ${labels.join(' & ')}`;
  }

  const label = mapping[stageLink];
  if (label) {
    // If it's a code, prefix it for clarity
    if (stageLink.startsWith('S') && stageLink.length === 2) {
      return `${stageLink}: ${label}`;
    }
    return label;
  }

  return stageLink;
};
